#include <vector>
#include <queue>
#include <unordered_map>
#include <climits>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the graph
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    unordered_map<long long, vector<pair<long long, long long>>> reverse_edges;
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        graph[u].emplace_back(v, w);
        reverse_edges[v].emplace_back(u, w);
    }

    // Priority queue: (total_cost, current_node, used_switch)
    priority_queue<pair<long long, pair<long long, bool>>, 
                   vector<pair<long long, pair<long long, bool>>>, 
                   greater<pair<long long, pair<long long, bool>>>> heap;
    heap.push({0, {0, false}});

    // Visited: (node, used_switch) -> min_cost
    unordered_map<long long, unordered_map<bool, long long>> visited;
    visited[0][false] = 0;
    visited[0][true] = LLONG_MAX;

    while (!heap.empty()) {
        auto current = heap.top();
        heap.pop();
        long long current_cost = current.first;
        long long u = current.second.first;
        bool used_switch = current.second.second;

        if (u == n - 1) {
            return current_cost;
        }

        if (current_cost > visited[u][used_switch]) {
            continue;
        }

        // Option 1: Normal move without using any switch
        for (const auto& edge : graph[u]) {
            long long v = edge.first;
            long long w = edge.second;
            long long new_cost = current_cost + w;
            if (visited[v].find(used_switch) == visited[v].end() || new_cost < visited[v][used_switch]) {
                visited[v][used_switch] = new_cost;
                heap.push({new_cost, {v, used_switch}});
            }
        }

        // Option 2: Use the switch at node u (if not used before)
        if (!used_switch) {
            for (const auto& edge : reverse_edges[u]) {
                long long v = edge.first;
                long long w = edge.second;
                long long new_cost = current_cost + 2 * w;
                if (visited[v].find(true) == visited[v].end() || new_cost < visited[v][true]) {
                    visited[v][true] = new_cost;
                    heap.push({new_cost, {v, true}});
                }
            }
        }
    }

    // Check both possibilities (used switch or not) for the target node
    long long res = LLONG_MAX;
    if (visited[n - 1].find(false) != visited[n - 1].end()) {
        res = min(res, visited[n - 1][false]);
    }
    if (visited[n - 1].find(true) != visited[n - 1].end()) {
        res = min(res, visited[n - 1][true]);
    }

    return res != LLONG_MAX ? res : -1;
}
